class SurveyResultsPage{constructor(){this.surveyId=this.getSurveyIdFromUrl(),this.init()}getSurveyIdFromUrl(){const e=window.location.pathname.split("/"),s=e.indexOf("surveys");return parseInt(e[s+1])}async init(){await this.loadResults()}async loadResults(){const e=document.getElementById("loading"),s=document.getElementById("error-message"),t=document.getElementById("results-container");if(e&&s&&t)try{e.classList.remove("hidden"),s.classList.add("hidden"),t.classList.add("hidden");const n=await window.app.apiRequest(`/surveys/${this.surveyId}/results/data`),a=document.getElementById("survey-title"),d=document.getElementById("survey-description"),r=document.getElementById("total-responses");a&&(a.textContent=n.survey.title),d&&(d.textContent=n.survey.description||""),r&&(r.textContent=`${n.total_responses} ответов`),this.renderQuestionResults(n.question_results),e.classList.add("hidden"),t.classList.remove("hidden")}catch(t){e.classList.add("hidden"),s.classList.remove("hidden"),s&&(s.textContent="Ошибка загрузки результатов. Возможно, у вас нет доступа к этим результатам.")}}renderQuestionResults(e){const s=document.getElementById("questions-results");s&&(s.innerHTML="",e&&0!==e.length?e.forEach(e=>{const t=document.createElement("div");t.className="question-result";let n=`<h4>${e.question.text}</h4>`;"single_choice"===e.question.type?(n+='<div class="answer-stats">',e.answers&&e.answers.length>0?e.answers.forEach(s=>{const t=e.question.survey_id?Math.round(s.count/this.getTotalResponses(e.answers)*100):0;n+=`\n                            <div class="answer-stat">\n                                <span class="answer-text">${s.value}</span>\n                                <span class="answer-count">${s.count} (${t}%)</span>\n                            </div>\n                        `}):n+='<p class="no-answers">Пока нет ответов</p>',n+="</div>"):"text"===e.question.type&&(n+='<div class="answer-stats">',e.answers&&e.answers.length>0?e.answers.forEach(e=>{n+=`\n                            <div class="answer-stat">\n                                <span class="answer-text">${e.value}</span>\n                                <span class="answer-count">1 ответ</span>\n                            </div>\n                        `}):n+='<p class="no-answers">Пока нет ответов</p>',n+="</div>"),t.innerHTML=n,s.appendChild(t)}):s.innerHTML='<div class="empty-state"><h2>Результатов не найдено</h2><p>У этого опроса пока нет результатов.</p></div>')}getTotalResponses(e){return e.reduce((e,s)=>e+s.count,0)}}document.addEventListener("DOMContentLoaded",()=>{new SurveyResultsPage});